+fn coalescer_depth_decrement(depth: &AtomicU64, drained: u64) -> u64 {
+    depth
+        .fetch_update(Ordering::Relaxed, Ordering::Relaxed, |cur| {
+            Some(cur.saturating_sub(drained))
+        })
+        .unwrap_or(0)
+        .saturating_sub(drained)
+}
